module RefModule (
    input clk,
    input rst,
    input req,
    output reg busy
);
    parameter N = 5; // Number of cycles to remain busy
    reg [2:0] unused_count; // 3-bit counter to unused_count cycles

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            busy <= 0;
            unused_count <= 0;
        end else if (req && !busy) begin
            busy <= 1;
            unused_count <= 0;
        end else if (busy) begin
            if (unused_count < N - 1) begin
                unused_count <= unused_count + 1;
            end else begin
                busy <= 0;
            end
        end
    end
endmodule
